import axios from 'axios';

const BASE_URLS = [
  'http://localhost:8080/api/payment',
  'http://localhost:8080/api/payments',
];

async function requestWithFallback(requests) {
  let lastError;
  for (const request of requests) {
    try {
      const response = await request();
      return response.data;
    } catch (err) {
      if (err?.response?.status === 401 || err?.response?.status === 403) {
        throw err;
      }
      lastError = err;
    }
  }
  throw lastError;
}

function paymentRequests(pathBuilder, method = 'get', body = undefined) {
  return BASE_URLS.map((base) => () => axios({
    method,
    url: pathBuilder(base),
    data: body,
  }));
}

export const paymentService = {
  getAll: () => requestWithFallback(paymentRequests((base) => base, 'get')),
  getByMember: (memberId) => requestWithFallback([
    ...paymentRequests((base) => `${base}/member/${memberId}`, 'get'),
    ...paymentRequests((base) => `${base}/members/${memberId}`, 'get'),
    ...paymentRequests((base) => `${base}/by-member/${memberId}`, 'get'),
  ]),
  createForFine: (fineId, payload = {}) => requestWithFallback([
    ...paymentRequests((base) => base, 'post', { fineId, ...payload }),
    ...paymentRequests((base) => `${base}/fine/${fineId}`, 'post', payload),
    ...paymentRequests((base) => `${base}/${fineId}`, 'post', payload),
    ...paymentRequests((base) => `${base}/pay/${fineId}`, 'post', payload),
  ]),
};
